// Check approval queue and skip notification if empty.
// Hardened: wraps in try/catch to prevent 'Unknown error' crashes on bad API responses.
try {
  const input = $input.first();
  if (!input || !input.json) {
    console.warn('[approval-digest] No response from /digest endpoint — skipping.');
    return [];
  }
  const digest = input.json.digest;
  if (!digest || digest.totalPending === 0) {
    console.log('[approval-digest] Approval queue is empty — skipping notification.');
    return [];
  }
  return [{ json: digest }];
} catch (err) {
  console.error('[approval-digest] Check queue error:', err.message || String(err));
  return [];
}

// Check stale items and skip notification if none.
// Hardened: wraps in try/catch to prevent 'Unknown error' crashes on bad API responses.
try {
  const input = $input.first();
  if (!input || !input.json) {
    console.warn('[stale-digest] No response from /digest endpoint — skipping.');
    return [];
  }
  const digest = input.json.digest;
  if (!digest || digest.totalStale === 0) {
    console.log('[stale-digest] No stale opportunities — skipping stale notification.');
    return [];
  }
  return [{ json: digest }];
} catch (err) {
  console.error('[stale-digest] Check stale error:', err.message || String(err));
  return [];
}
